import React from 'react';
import { useNavigate } from 'react-router-dom';

const CourseCard = ({ course }) => {
  const navigate = useNavigate();

  const handleClick = () => {
    navigate(`/course/${course.id}`);
  };

  // ✅ Course icon based on name
  const getCourseIcon = (name) => {
    const nameLower = name?.toLowerCase() || '';
    if (nameLower.includes('btech') || nameLower.includes('b.tech')) return '💻';
    if (nameLower.includes('bca')) return '📱';
    if (nameLower.includes('bba')) return '📊';
    if (nameLower.includes('mba')) return '🎓';
    if (nameLower.includes('mca')) return '💼';
    if (nameLower.includes('b.com') || nameLower.includes('bcom')) return '💰';
    if (nameLower.includes('ba')) return '📖';
    return '📚';
  };

  // ✅ Format course name
  const formatCourseName = (name) => {
    if (!name) return '';
    if (name.toLowerCase().includes('btech') || name.toLowerCase().includes('b.tech')) {
      return name.replace(/btech|b.tech/i, 'B.Tech').trim();
    }
    if (name.toLowerCase().includes('bca')) return 'BCA';
    if (name.toLowerCase().includes('bba')) return 'BBA';
    if (name.toLowerCase().includes('mba')) return 'MBA';
    if (name.toLowerCase().includes('mca')) return 'MCA';
    return name;
  };

  // ✅ Format branch
  const formatBranch = (branch, courseName) => {
    if (!branch || branch === 'General' || branch === 'All') {
      if (courseName?.toLowerCase().includes('btech')) return 'Computer Science';
      if (courseName?.toLowerCase().includes('bca')) return 'Computer Applications';
      if (courseName?.toLowerCase().includes('bba')) return 'Business Administration';
      if (courseName?.toLowerCase().includes('mba')) return 'Business Administration';
      if (courseName?.toLowerCase().includes('mca')) return 'Computer Applications';
      return 'General';
    }
    return branch;
  };

  const styles = {
    card: {
      background: 'white',
      borderRadius: '16px',
      padding: '2rem 1.5rem',
      boxShadow: '0 4px 6px rgba(0, 0, 0, 0.1)',
      textAlign: 'center',
      transition: 'all 0.3s ease',
      cursor: 'pointer',
      border: '1px solid #e5e7eb',
      height: '100%',
      display: 'flex',
      flexDirection: 'column',
      justifyContent: 'center',
      alignItems: 'center',
      position: 'relative',
      overflow: 'hidden'
    },
    cardIcon: {
      fontSize: '3rem',
      marginBottom: '1rem',
      transition: 'transform 0.3s',
      background: 'linear-gradient(135deg, #f3f4f6, #e5e7eb)',
      width: '80px',
      height: '80px',
      borderRadius: '50%',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      margin: '0 auto 1rem'
    },
    cardTitle: {
      fontSize: '1.3rem',
      fontWeight: '700',
      color: '#1f2937',
      marginBottom: '0.5rem',
      lineHeight: '1.4'
    },
    cardBranch: {
      color: '#6b7280',
      fontSize: '0.95rem',
      marginBottom: '0.5rem'
    },
    codeBadge: {
      position: 'absolute',
      top: '15px',
      right: '15px',
      background: '#dbeafe',
      color: '#1d4ed8',
      padding: '4px 10px',
      borderRadius: '20px',
      fontSize: '0.75rem',
      fontWeight: '600'
    },
    statsContainer: {
      display: 'flex',
      gap: '1.5rem',
      marginTop: '1rem',
      padding: '0.75rem 1rem',
      background: '#f9fafb',
      borderRadius: '12px',
      width: '100%',
      justifyContent: 'center'
    },
    statItem: {
      display: 'flex',
      alignItems: 'center',
      gap: '0.5rem',
      color: '#4b5563',
      fontSize: '0.9rem'
    },
    popularityBadge: {
      position: 'absolute',
      top: '15px',
      left: '15px',
      background: '#fef3c7',
      color: '#92400e',
      padding: '4px 10px',
      borderRadius: '20px',
      fontSize: '0.75rem',
      fontWeight: '600',
      display: 'flex',
      alignItems: 'center',
      gap: '0.25rem'
    }
  };

  // Popularity badge
  const getPopularityBadge = () => {
    const notes = course.notes || course.note_count || 0;
    const pyqs = course.pyqs || course.pyq_count || 0;
    const totalResources = notes + pyqs;
    if (totalResources > 50) return '🔥 Hot';
    if (totalResources > 30) return '⭐ Popular';
    if (totalResources > 15) return '📈 Trending';
    return null;
  };

  const popularityBadge = getPopularityBadge();
  const courseIcon = getCourseIcon(course.name);
  const formattedName = formatCourseName(course.name);
  const formattedBranch = formatBranch(course.branch, course.name);
  const notesCount = course.notes || course.note_count || 0;
  const pyqsCount = course.pyqs || course.pyq_count || 0;

  return (
    <div 
      style={styles.card} 
      onClick={handleClick}
      onMouseEnter={(e) => {
        e.currentTarget.style.transform = 'translateY(-8px)';
        e.currentTarget.style.boxShadow = '0 20px 40px rgba(79, 70, 229, 0.2)';
        e.currentTarget.style.borderColor = '#4f46e5';
      }}
      onMouseLeave={(e) => {
        e.currentTarget.style.transform = 'translateY(0)';
        e.currentTarget.style.boxShadow = '0 4px 6px rgba(0, 0, 0, 0.1)';
        e.currentTarget.style.borderColor = '#e5e7eb';
      }}
    >
      {/* Popularity Badge */}
      {popularityBadge && (
        <div style={styles.popularityBadge}>
          {popularityBadge}
        </div>
      )}

      {/* Course Code Badge */}
      {course.code && (
        <div style={styles.codeBadge}>
          {course.code}
        </div>
      )}

      {/* Icon */}
      <div style={styles.cardIcon}>
        {courseIcon}
      </div>

      {/* Content */}
      <h3 style={styles.cardTitle}>{formattedName}</h3>
      <p style={styles.cardBranch}>
        {formattedBranch} • Sem {course.semester || 'All'}
      </p>

      {/* Stats */}
      <div style={styles.statsContainer}>
        <div style={styles.statItem}>
          <span style={{ fontSize: '1.1rem' }}>📄</span>
          <span>{notesCount} Notes</span>
        </div>
        <div style={styles.statItem}>
          <span style={{ fontSize: '1.1rem' }}>📝</span>
          <span>{pyqsCount} PYQs</span>
        </div>
      </div>

      {/* Click Hint */}
      <div style={{
        marginTop: '1rem',
        fontSize: '0.8rem',
        color: '#9ca3af',
        display: 'flex',
        alignItems: 'center',
        gap: '0.3rem'
      }}>
        <span>👆</span> Click to view course details
      </div>
    </div>
  );
};

export default CourseCard;
